  "translated_query_code": "import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;
import org.springframework.data.domain.Sort;
import org.springframework.data.mongodb.core.MongoTemplate;
import org.springframework.data.mongodb.core.aggregation.Aggregation;
import org.springframework.data.mongodb.core.aggregation.TypedAggregation;
import org.springframework.data.mongodb.core.query.Criteria;
import org.springframework.data.mongodb.core.query.Query;

class MongoQueryEntrypoint {
    private final MongoTemplate mongoTemplate;

    MongoQueryEntrypoint(MongoTemplate mongoTemplate) {
        this.mongoTemplate = mongoTemplate;
    }

    List<OrderLine> query1() {
        LocalDateTime from = LocalDateTime.of(2014, 12, 20, 0, 0);
        LocalDateTime to = LocalDateTime.of(2014, 12, 31, 0, 0);
        Query query = new Query(Criteria.where("pickingCompletedWhen").gte(from).lte(to));
        return mongoTemplate.find(query, OrderLine.class);
    }

    List<Order> query2() {
        Query query = new Query(Criteria.where("customerId").is(1));
        return mongoTemplate.find(query, Order.class);
    }

    List<Map> query3() {
        TypedAggregation<OrderLine> aggregation = Aggregation.newAggregation(
            OrderLine.class,
            Aggregation.group("taxRate").count().as("count"),
            Aggregation.project("count").and("taxRate").previousOperation(),
            Aggregation.sort(Sort.Direction.DESC, "count")
        );
        return mongoTemplate.aggregate(aggregation, Map.class).getMappedResults();
    }

    List<OrderLine> query4() {
        Query query = new Query().with(Sort.by(Sort.Direction.DESC, "quantity")).limit(50);
        return mongoTemplate.find(query, OrderLine.class);
    }

    List<Map> query5() {
        Query query = new Query();
        query.fields().include("orderLineId", "quantity");
        return mongoTemplate.find(query, Map.class, "orderLines");
    }
}"
  , "source_validation_harness_code": "public static IQueryable<OrderLine> Query1(SandboxDbContext ctx)
{
  var from = new DateTime(2014, 12, 20);
  var to = new DateTime(2014, 12, 31);
  return ctx.OrderLines.Where(ol => ol.PickingCompletedWhen >= from && ol.PickingCompletedWhen <= to);
}

public static IQueryable<Order> Query2(SandboxDbContext ctx)
{
  return ctx.Orders
    .Include(o => o.Customer)
      .ThenInclude(c => c.CustomerTransactions)
    .Include(o => o.OrderLines)
    .AsSplitQuery()
    .Where(c => c.CustomerID == 1);
}

public static IQueryable<dynamic> Query3(SandboxDbContext ctx)
{
  return ctx.OrderLines.GroupBy(ol => ol.TaxRate).Select(g => new { TaxRate = g.Key, Count = g.Count() }).OrderByDescending(x => x.Count);
}

public static IQueryable<OrderLine> Query4(SandboxDbContext ctx)
{
  return ctx.OrderLines.OrderByDescending(ol => ol.Quantity).Take(50);
}

public static IQueryable<dynamic> Query5(SandboxDbContext ctx)
{
  return ctx.OrderLines.Select(ol => new { ol.OrderLineID, ol.Quantity });
}"
